   245→				if tempDelay == 0 {
   246→					tempDelay = 5 * time.Millisecond
   247→				} else {
   248→					tempDelay *= 2
   249→				}
   250→				if max := 1 * time.Second; tempDelay > max {
   251→					tempDelay = max
   252→				}
   253→				time.Sleep(tempDelay)
   254→				continue
   255→			}
   256→			return e
   257→		}
   258→		go srv.HandleConn(conn)
   259→	}
   260→}
