   391→func (srv *Server) closeDoneChanLocked() {
   392→	ch := srv.getDoneChanLocked()
   393→	select {
   394→	case <-ch:
   395→		// Already closed. Don't close again.
   396→	default:
   397→		// Safe to close here. We're the only closer, guarded
   398→		// by srv.mu.
   399→		close(ch)
   400→	}
   401→}
